import { useImportLocale } from '../../config-provider/hooks/useImportLocale';
import type { LocaleName } from '@universe-design/react-provider';
import enUS from './locales/en-US';

export type OrganizationNameTagLocaleType = typeof enUS;

export const importOrganizationNameTagLocale = async (locale: LocaleName) => {
  let promise;
  if (process.env.__BUILD__ === 'babel') {
    promise = import(`./locales/${locale}.js`);
  } else if (process.env.__BUILD__ === 'rollup') {
    promise = import(`./locales/${locale}.ts`);
  } else {
    promise = import(`./locales/${locale}`);
  }
  return promise.then(({ default: localeData }) => localeData as OrganizationNameTagLocaleType);
};

export const useOrganizationNameTagLocale = () =>
  useImportLocale({
    importLocale: importOrganizationNameTagLocale,
    fallbackLocale: enUS,
  });
